const express = require('express');
const path = require('path');
const app = express();
const port = 3000;

// Serve static files from the current directory
app.use(express.static(path.join(__dirname)));

app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

app.listen(port, () => {
  console.log(`Todo app server listening at http://localhost:${port}`);
  console.log('To run this server, ensure you have Node.js and Express installed (npm install express).');
  console.log('Then run: node server.js');
  console.log('\nTo run tests, make sure this server is running and then execute: npx playwright test');
});

