import { test, expect } from '@playwright/test';

test.describe('Todo Application', () => {
    // Before each test, navigate to the application page
    test.beforeEach(async ({ page }) => {
        // Assuming the server.js is running and serving index.html on port 3000
        await page.goto('http://localhost:3000');
    });

    test('should display the application title', async ({ page }) => {
        await expect(page.locator('h1')).toHaveText('My Todo List');
    });

    test('should allow adding a new todo item and clear the input', async ({ page }) => {
        const todoInput = page.locator('#todoInput');
        const addBtn = page.locator('#addBtn');
        const todoList = page.locator('#todoList');

        const taskText = 'Learn Playwright testing';

        // 1. Type task into the input field
        await todoInput.fill(taskText);
        await expect(todoInput).toHaveValue(taskText);

        // 2. Click the Add Task button
        await addBtn.click();

        // 3. Verify the item is added to the list
        const firstListItem = todoList.locator('li').first();
        await expect(firstListItem).toBeVisible();
        await expect(firstListItem).toContainText(taskText);

        // 4. Verify the input box is cleared
        await expect(todoInput).toHaveValue('');
    });

    test('should allow adding multiple todo items and clear input each time', async ({ page }) => {
        const todoInput = page.locator('#todoInput');
        const addBtn = page.locator('#addBtn');
        const todoList = page.locator('#todoList');

        const tasks = ['Buy groceries', 'Walk the dog', 'Finish project report'];

        for (const task of tasks) {
            await todoInput.fill(task);
            await addBtn.click();
            // Verify each task is added and input is cleared
            await expect(todoList.locator('li', { hasText: task })).toBeVisible();
            await expect(todoInput).toHaveValue('');
        }

        // Verify total number of items in the list
        await expect(todoList.locator('li')).toHaveCount(tasks.length);
    });

    test('should not add an empty todo item and show an alert', async ({ page }) => {
        const todoInput = page.locator('#todoInput');
        const addBtn = page.locator('#addBtn');
        const todoList = page.locator('#todoList');

        // Listen for dialogs (alerts) that might appear
        page.on('dialog', async dialog => {
            expect(dialog.message()).toContain('Task cannot be empty!');
            await dialog.accept(); // Dismiss the alert
        });

        // Try adding an empty task
        await todoInput.fill('');
        await addBtn.click();

        // Verify no items were added to the list
        await expect(todoList.locator('li')).toHaveCount(0);
        // Verify input remains empty
        await expect(todoInput).toHaveValue('');
    });

    test('should allow deleting a todo item', async ({ page }) => {
        const todoInput = page.locator('#todoInput');
        const addBtn = page.locator('#addBtn');
        const todoList = page.locator('#todoList');

        const task1 = 'Task to delete';
        const task2 = 'Another task to keep';

        // Add two tasks to the list
        await todoInput.fill(task1);
        await addBtn.click();
        await todoInput.fill(task2);
        await addBtn.click();

        await expect(todoList.locator('li')).toHaveCount(2);

        // Find the list item containing task1 and click its delete button
        const taskToDelete = todoList.locator('li', { hasText: task1 });
        await expect(taskToDelete).toBeVisible();
        await taskToDelete.locator('.delete-btn').click();

        // Verify the first task is gone, and only one item remains
        await expect(taskToDelete).not.toBeVisible();
        await expect(todoList.locator('li')).toHaveCount(1);
        await expect(todoList.locator('li', { hasText: task2 })).toBeVisible();
    });
});
